INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (26, 1, 26, '【読解】「田中さんは毎朝６時に起きて、朝ごはんを食べてから会社に行きます。週末はよく家族と買い物をします。」田中さんは＿＿と買い物をしますか。', 'single_choice', 1);
