INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (29, 1, 29, '１か月に日本語の本を何＿＿読みますか。', 'single_choice', 1);
INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (30, 1, 30, '【読解】「来週、会社で大きいプロジェクトが始まります。わたしはリーダーになったので、とても忙しくなりそうです。」筆者は来週からどうなりそうですか。', 'single_choice', 1);
INSERT INTO "level_up_questions" ("id", "test_id", "order_index", "text", "type", "points") VALUES (31, 1, 31, '日本では、春になると桜が咲く＿＿です。', 'single_choice', 1);
